def get_user_name(user_dict):
    try:
        return user_dict['name']
    except KeyError:
        return 'Anonymous'

print(get_user_name({'id': 1, 'name': 'Alice'}))
print(get_user_name({'id': 2}))

code_walkthrough.code:
def parse_age(value):
    try:
        age = int(value)
        print(f"Age is {age}")
    except ValueError as e:
        print(f"Invalid input: {e}")

parse_age('twenty')

