challenge.solution:
def handle_request(payload):
    try:
        age = int(payload['user']['age'])
        print(f'Age is {age}')
    except KeyError:
        print('Missing field')
    except ValueError:
        print('Invalid format')

handle_request({'user': {}})
handle_request({'user': {'age': 'abc'}})

